const input = $('Parse LLM Output').first().json;
const role = input.requester_role;
const action = input.parsed_action;
const jurisdiction = input.jurisdiction || null;
const facts = input.facts || {};

const VALID_ACTIONS = ["cohort_construction", "clinical_notes_access", "aggregate_statistics", "record_export"];

if (action === null || action === undefined || !VALID_ACTIONS.includes(action)) {
  return [{
    json: Object.assign({}, input, {
      access_decision: {
        agent: "AccessControl",
        action: action,
        jurisdiction: jurisdiction,
        decision: "deny",
        policies_consulted: ["POL-FAIL-CLOSED"],
        scope_granted: null,
        preconditions_satisfied: null,
        rationale: "Classifier returned no valid action label. Failing closed."
      }
    })
  }];
}

let policies;
try {
  const fetched = $('HTTP Request').first().json.data;
  const parsed = JSON.parse(fetched);
  policies = parsed.policies;
  if (!Array.isArray(policies)) {
    throw new Error("Fetched policy payload has no policies array");
  }
} catch (e) {
  return [{
    json: Object.assign({}, input, {
      access_decision: {
        agent: "AccessControl",
        action: action,
        jurisdiction: jurisdiction,
        decision: "deny",
        policies_consulted: ["POL-FETCH-FAILED"],
        scope_granted: null,
        preconditions_satisfied: null,
        rationale: "Policy source unavailable or unparseable. Failing closed. Detail: " + e.message
      }
    })
  }];
}

function jurisdictionMatches(p) {
  return !p.jurisdiction || p.jurisdiction === jurisdiction;
}

function appliesWhenMatches(pre) {
  if (!pre.applies_when) return true;
  for (const key in pre.applies_when) {
    if (input[key] !== pre.applies_when[key]) return false;
  }
  return true;
}

const applicable = policies.filter(function(p) {
  return p.applies_to_role === role || p.applies_to_role === "*";
});
const consulted = applicable.map(function(p) { return p.policy_id; });

let decision = "pending";
let rationale = "No applicable policy permits this action";
let scope = null;
let preconditionsSatisfied = null;

// Forbid loop (jurisdiction-aware)
for (const p of applicable) {
  if (!jurisdictionMatches(p)) continue;
  const forbids = p.forbids || [];
  if (forbids.indexOf(action) !== -1) {
    decision = "deny";
    rationale = "Denied by " + p.policy_id + ": " + p.name;
    break;
  }
}

// Permit loop (jurisdiction-aware, precondition-gated). First matching jurisdiction permit governs.
if (decision === "pending") {
  for (const p of applicable) {
    if (!jurisdictionMatches(p)) continue;
    const permits = p.permits || [];
    if (permits.indexOf(action) === -1) continue;

    const pres = p.preconditions || [];
    let failed = null;
    const satisfied = [];
    for (const pre of pres) {
      if (!appliesWhenMatches(pre)) continue;
      const factName = pre.requires;
      if (!(factName in facts)) {
        failed = { code: "POL-PRECONDITION-UNVERIFIABLE", pre: pre };
        break;
      }
      if (facts[factName] !== true) {
        failed = { code: "POL-PRECONDITION-UNMET", pre: pre };
        break;
      }
      satisfied.push({ precondition_id: pre.precondition_id, basis: pre.basis });
    }

    if (failed) {
      decision = "deny";
      scope = null;
      consulted.push(failed.code);
      rationale = "Permitted by " + p.policy_id + " but precondition " + failed.pre.precondition_id +
        " (" + failed.pre.basis + ") " +
        (failed.code === "POL-PRECONDITION-UNMET"
          ? "is not met. Failing closed."
          : "could not be verified from the request. Failing closed.");
    } else {
      decision = "allow";
      scope = p.scope || null;
      preconditionsSatisfied = satisfied.length ? satisfied : null;
      rationale = "Allowed by " + p.policy_id + ": " + p.name +
        (satisfied.length ? " (preconditions satisfied)" : "");
    }
    break;
  }
}

// Jurisdiction-gated action, but the request carried no jurisdiction
if (decision === "pending" && jurisdiction === null) {
  const jurisdictionGated = applicable.some(function(p) {
    const permits = p.permits || [];
    return permits.indexOf(action) !== -1 && p.jurisdiction;
  });
  if (jurisdictionGated) {
    decision = "deny";
    consulted.push("POL-NO-JURISDICTION");
    rationale = "Action '" + action + "' is jurisdiction-gated but the request carried no jurisdiction. Failing closed.";
  }
}

if (decision === "pending") {
  decision = "deny";
  rationale = "No applicable policy permits this action" +
    (jurisdiction ? " in jurisdiction " + jurisdiction : "") + ".";
}

return [{
  json: Object.assign({}, input, {
    access_decision: {
      agent: "AccessControl",
      action: action,
      jurisdiction: jurisdiction,
      decision: decision,
      policies_consulted: consulted,
      scope_granted: scope,
      preconditions_satisfied: preconditionsSatisfied,
      rationale: rationale
    }
  })
}];

// Audit and Lineage - DAY 6
// Assembles the governance receipt with framework mapping and hash.

const crypto = require('crypto');
const input = $input.first().json;

// Collect every agent's decision in the order they fired
const decisions = [];
if (input.access_decision) decisions.push(input.access_decision);
// Future agents (Data Quality, Analytics) will add their decisions here
// after Phase 3 builds those branches.

// Map current capabilities to NIST AI RMF functions
const nistMapping = ["GOVERN-1.1", "MAP-3.4"];
if (input.access_decision && input.access_decision.decision === "deny") {
  nistMapping.push("MANAGE-4.1");
}

// PHIPA principles touched in this request
const phipaPrinciples = new Set();
for (const d of decisions) {
  if (d.phipa_principle) phipaPrinciples.add(d.phipa_principle);
}
phipaPrinciples.add("accountability"); // POL-004 always applies

const outcome = (input.access_decision && input.access_decision.decision === "allow")
  ? "allowed"
  : "denied";

const receipt = {
  receipt_id: input.receipt_id,
  timestamp: input.timestamp,
  request: {
    raw_text: input.request_text,
    requester_role: input.requester_role,
    purpose: input.purpose,
    parsed_action: input.parsed_action
  },
  decisions: decisions,
  framework_mapping: {
    nist_ai_rmf: nistMapping,
    phipa_principles: Array.from(phipaPrinciples)
  },
  outcome: outcome
};

// Hash the receipt for tamper-evidence
const hashable = JSON.stringify(receipt);
receipt.final_artifact_hash = crypto
  .createHash('sha256')
  .update(hashable)
  .digest('hex');

return [{ json: { receipt: receipt } }];

// Parse Claude's response into structured fields
const llmItem = $input.first().json;
const previousItem = $('Edit Fields').first().json;

// Extract the raw text from Claude's output
let rawText = "";
if (Array.isArray(llmItem.content) && llmItem.content[0]?.text) {
  rawText = llmItem.content.map(c => c.text || "").join("");
} else if (llmItem.message && llmItem.message.content) {
  if (Array.isArray(llmItem.message.content)) {
    rawText = llmItem.message.content.map(c => c.text || "").join("");
  } else {
    rawText = llmItem.message.content;
  }
} else if (typeof llmItem.content === "string") {
  rawText = llmItem.content;
} else if (llmItem.text) {
  rawText = llmItem.text;
}

// Strip code fences and parse
let parsed = null;
let parseError = null;
try {
  const cleaned = rawText.replace(/^\s*```json\s*/i, '').replace(/\s*```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parseError = e.message;
  parsed = {
    action: null,
    purpose: "LLM output could not be parsed"
  };
}

// Discard any role the LLM may have returned. Role is an authenticated
// input from the request envelope, never an LLM inference.
if (parsed && typeof parsed === 'object') {
  delete parsed.requester_role;
}

// Merge: keep original input, add parsed fields. Role passes through
// untouched from the form. Action comes only from the classifier with
// no fail-open default; downstream nodes must handle a null action.
return [{
  json: {
    ...previousItem,
    parsed_request: parsed,
    parsed_action: parsed.action || null,
    llm_parse_error: parseError
  }
}];

// Data Quality Agent: two in-scope checks on a FHIR collection bundle.
// Checks: (1) missing required field on Observations (status, code present)
//         (2) terminology allowlist membership (Observation + Condition codes)
// Emits: flags array + summary, fail-closed on parse/shape failure.
// Provenance (dataset, bundle_path) is read from Resolve Dataset directly,
// because the HTTP Request (Fetch Bundle) replaces the item with its response
// body and does not carry the selector fields forward.

const input = $input.first().json;
const prov = $('Resolve Dataset').first().json;

// Fail closed if the fetch did not deliver a string under data.
if (typeof input.data !== 'string') {
  return [{
    json: {
      dataset: prov.dataset || null,
      bundle_path: prov.bundle_path || null,
      dq_error: 'BUNDLE-FETCH-SHAPE-INVALID',
      flags: [],
      flag_count: 0,
      total_resources: 0
    }
  }];
}

let bundle;
try {
  bundle = JSON.parse(input.data);
} catch (e) {
  return [{
    json: {
      dataset: prov.dataset || null,
      bundle_path: prov.bundle_path || null,
      dq_error: 'BUNDLE-PARSE-FAILED',
      flags: [],
      flag_count: 0,
      total_resources: 0
    }
  }];
}

// Closed value sets (allowlist). Codes present but not listed are flagged.
const ALLOWED_OBS_CODES = ['8310-5'];
const ALLOWED_CONDITION_CODES = ['E11.9'];

const entries = Array.isArray(bundle.entry) ? bundle.entry : [];
const flags = [];

for (const e of entries) {
  const r = e && e.resource ? e.resource : null;
  if (!r) continue;

  const id = r.id || '(no-id)';
  const type = r.resourceType || '(no-type)';

  // Check 1: missing required field, Observations only (completeness).
  if (type === 'Observation') {
    if (r.status === undefined || r.status === null) {
      flags.push({
        resource_id: id,
        resource_type: type,
        check: 'missing_required_field',
        concern: 'completeness',
        detail: 'Observation.status is missing'
      });
    }
    if (r.code === undefined || r.code === null) {
      flags.push({
        resource_id: id,
        resource_type: type,
        check: 'missing_required_field',
        concern: 'completeness',
        detail: 'Observation.code is missing'
      });
    }
  }

  // Check 2: terminology allowlist (conformance).
  // Only evaluated when a code is actually present, so a missing code
  // is reported once by Check 1, not double-reported here.
  if (type === 'Observation' && r.code) {
    const coding = r.code.coding && r.code.coding[0] ? r.code.coding[0] : null;
    const codeVal = coding ? coding.code : undefined;
    if (codeVal !== undefined && !ALLOWED_OBS_CODES.includes(codeVal)) {
      flags.push({
        resource_id: id,
        resource_type: type,
        check: 'invalid_terminology_code',
        concern: 'conformance',
        detail: 'Observation code ' + codeVal + ' not in allowlist'
      });
    }
  }

  if (type === 'Condition' && r.code) {
    const coding = r.code.coding && r.code.coding[0] ? r.code.coding[0] : null;
    const codeVal = coding ? coding.code : undefined;
    if (codeVal !== undefined && !ALLOWED_CONDITION_CODES.includes(codeVal)) {
      flags.push({
        resource_id: id,
        resource_type: type,
        check: 'invalid_terminology_code',
        concern: 'conformance',
        detail: 'Condition code ' + codeVal + ' not in allowlist'
      });
    }
  }
}

return [{
  json: {
    dataset: prov.dataset || null,
    bundle_path: prov.bundle_path || null,
    total_resources: entries.length,
    flags: flags,
    flag_count: flags.length
  }
}];

// Audit DQ - Data Quality lineage receipt (Day 14)
// Mirrors the Audit and Lineage receipt discipline: same id/timestamp format,
// same decisions-array container, same SHA-256 tamper-evidence.
// Differs in payload: carries a data-quality assessment, not an access decision.
// No phipa_principles block: an internal integrity check makes no access
// decision, so PHIPA principles are not engaged (documented in mapping_note).

const crypto = require('crypto');
const input = $input.first().json;

// Mint id and timestamp in the SAME format as the access receipts.
// Matches the access-chain Edit Fields convention exactly:
//   receipt_id = $now.toMillis() + "-" + Math.floor(Math.random()*100000)
//   timestamp  = $now.toISO()  (local offset, e.g. -04:00)
const receiptId = $now.toMillis() + "-" + Math.floor(Math.random() * 100000);
const timestamp = $now.toISO();

// The DQ agent's "decision" is its assessment, recorded in the same
// decisions-array container the access receipts use.
const dqDecision = {
  agent: "DataQuality",
  dataset: input.dataset || null,
  bundle_path: input.bundle_path || null,
  total_resources: (input.total_resources !== undefined) ? input.total_resources : null,
  flag_count: (input.flag_count !== undefined) ? input.flag_count : null,
  flags: Array.isArray(input.flags) ? input.flags : [],
  dq_error: input.dq_error || null
};

// clean when no flags, flagged when any flag present. If a fail-closed
// error came through, outcome is flagged (the run did not produce a clean read).
const outcome = (input.dq_error)
  ? "flagged"
  : ((input.flag_count === 0) ? "clean" : "flagged");

const nistMapping = ["MAP-3.4", "MEASURE-2.7"];

const receipt = {
  receipt_id: receiptId,
  timestamp: timestamp,
  request: {
    dataset: input.dataset || null,
    bundle_path: input.bundle_path || null
  },
  decisions: [dqDecision],
  framework_mapping: {
    nist_ai_rmf: nistMapping,
    mapping_note: "PHIPA principles not engaged: data quality is an internal integrity check, not an access decision."
  },
  outcome: outcome
};

// Hash for tamper-evidence, same discipline as Audit and Lineage:
// stringify the receipt, hash, then attach the hash field last.
const hashable = JSON.stringify(receipt);
receipt.final_artifact_hash = crypto
  .createHash('sha256')
  .update(hashable)
  .digest('hex');

return [{ json: { receipt: receipt } }];

// Audit DQ FailClosed - fail-closed lineage receipt for the guard's false branch.
// Fires when the dataset selector did not resolve to a known bundle path
// (Guard Bundle Path routed the item to false because bundle_path was null).
// Emits a receipt in the SAME shape as Audit DQ, recording the refusal,
// so a bad selector cannot bypass governance: every request leaves a receipt.

const crypto = require('crypto');
const input = $input.first().json;

// Same id/timestamp convention as the access receipts and Audit DQ.
const receiptId = $now.toMillis() + "-" + Math.floor(Math.random() * 100000);
const timestamp = $now.toISO();

// The item on the false branch still carries Resolve Dataset's output:
// dataset = the rejected selector value, bundle_path = null.
const dqDecision = {
  agent: "DataQuality",
  dataset: input.dataset || null,
  bundle_path: input.bundle_path || null,
  total_resources: null,
  flag_count: null,
  flags: [],
  dq_error: "DQ-FAIL-CLOSED"
};

const receipt = {
  receipt_id: receiptId,
  timestamp: timestamp,
  request: {
    dataset: input.dataset || null,
    bundle_path: input.bundle_path || null
  },
  decisions: [dqDecision],
  framework_mapping: {
    nist_ai_rmf: ["MAP-3.4", "MEASURE-2.7"],
    mapping_note: "PHIPA principles not engaged: data quality is an internal integrity check, not an access decision."
  },
  outcome: "flagged"
};

const hashable = JSON.stringify(receipt);
receipt.final_artifact_hash = crypto
  .createHash('sha256')
  .update(hashable)
  .digest('hex');

return [{ json: { receipt: receipt } }];

// Analytics Compute - Day 16
// Runs ONLY on the IF true branch: aggregate_statistics AND allow.
// Non-bypass is a property of the graph, not of a check in this file:
// this node's only inbound edge is the gate's true output.
//
// Reads the suppression threshold from the LIVE policy file by capability
// lookup (role + jurisdiction + permits aggregate_statistics), never by
// hardcoded policy id and never by hardcoded cell size. Swap is data.

const bundleRaw = $input.first().json.data;
const parentReceipt = $('Audit and Lineage').first().json.receipt;
const accessDecision = parentReceipt.decisions[0];

const role = accessDecision.agent ? parentReceipt.request.requester_role : null;
const jurisdiction = accessDecision.jurisdiction || null;

const flags = [];

// --- 1. Resolve the suppression threshold from the live policy file ---
let minimumCellSize = Infinity;   // fail closed: suppress everything
let thresholdSource = null;

try {
  const policyRaw = $('HTTP Request').first().json.data;
  const policies = JSON.parse(policyRaw).policies;

  const governing = policies.find(function (p) {
    const roleMatch = p.applies_to_role === role || p.applies_to_role === "*";
    const jurMatch = !p.jurisdiction || p.jurisdiction === jurisdiction;
    const permits = p.permits || [];
    return roleMatch && jurMatch && permits.indexOf("aggregate_statistics") !== -1;
  });

  if (!governing) {
    flags.push("No governing policy found for aggregate_statistics. Suppressing all cells.");
  } else {
    const pre = (governing.preconditions || []).find(function (x) {
      return x.requires === "small_cell_suppression_applied";
    });
    if (!pre || typeof pre.minimum_cell_size !== "number") {
      flags.push("Governing policy " + governing.policy_id +
        " declares no numeric minimum_cell_size. Suppressing all cells.");
    } else {
      minimumCellSize = pre.minimum_cell_size;
      thresholdSource = {
        policy_id: governing.policy_id,
        precondition_id: pre.precondition_id,
        basis: pre.basis
      };
    }
  }
} catch (e) {
  flags.push("Policy source unreadable for threshold resolution: " + e.message +
    ". Suppressing all cells.");
}

// --- 2. Parse the cohort bundle ---
let entries = [];
try {
  const bundle = JSON.parse(bundleRaw);
  entries = Array.isArray(bundle.entry) ? bundle.entry : [];
  if (entries.length === 0) {
    flags.push("Bundle contained no entries.");
  }
} catch (e) {
  flags.push("Cohort bundle unparseable: " + e.message);
}

// --- 3. Index patients, then find distinct diabetes patients ---
const DIABETES_CODE = "E11.9";

const genderById = {};
for (const entry of entries) {
  const r = entry.resource;
  if (r && r.resourceType === "Patient" && r.id) {
    genderById[r.id] = r.gender || "unknown";
  }
}

const diabetesPatientIds = new Set();
for (const entry of entries) {
  const r = entry.resource;
  if (!r || r.resourceType !== "Condition") continue;
  const codings = (r.code && r.code.coding) || [];
  const isDiabetes = codings.some(function (c) { return c.code === DIABETES_CODE; });
  if (!isDiabetes) continue;
  const ref = r.subject && r.subject.reference;
  if (!ref) continue;
  const pid = ref.split("/")[1];
  if (pid && genderById[pid] !== undefined) {
    diabetesPatientIds.add(pid);
  }
}

// --- 4. Count distinct patients by gender ---
const rawCounts = {};
for (const pid of diabetesPatientIds) {
  const g = genderById[pid];
  rawCounts[g] = (rawCounts[g] || 0) + 1;
}

// --- 5. Apply small-cell suppression ---
const cells = [];
let suppressedCellCount = 0;
for (const g of Object.keys(rawCounts).sort()) {
  const n = rawCounts[g];
  const suppress = n < minimumCellSize;
  if (suppress) suppressedCellCount++;
  cells.push({
    gender: g,
    count: suppress ? null : n,
    suppressed: suppress
  });
}

const analytics = {
  agent: "Analytics",
  query: {
    measure: "distinct_patient_count",
    condition_code: DIABETES_CODE,
    condition_system: "http://hl7.org/fhir/sid/icd-10-cm",
    group_by: "Patient.gender",
    bundle_path: "data/cohort_bundle.json"
  },
  safeguard: {
    name: "small_cell_suppression",
    minimum_cell_size: (minimumCellSize === Infinity) ? null : minimumCellSize,
    threshold_source: thresholdSource,
    enforced_by: "Analytics"
  },
  cohort_size: diabetesPatientIds.size,
  cells: cells,
  suppressed_cell_count: suppressedCellCount,
  flags: flags
};

return [{
  json: {
    analytics: analytics,
    access_receipt_id: parentReceipt.receipt_id,
    access_receipt_hash: parentReceipt.final_artifact_hash
  }
}];$input.item;

// Audit Analytics - Analytics governance receipt (Day 16)
// Mirrors Audit and Lineage and Audit DQ receipt discipline: same id/timestamp
// format, same decisions-array container, same SHA-256 tamper-evidence.
//
// Differs in one structural respect: this receipt CHAINS to its parent access
// receipt. The chain is what proves the computation was authorized. An analytics
// receipt with no valid parent is, by construction, unreachable: this node's
// only inbound path originates at the access gate's true output.

const crypto = require('crypto');
const input = $input.first().json;

// Mint id and timestamp in the SAME format as the access receipts.
const receiptId = $now.toMillis() + "-" + Math.floor(Math.random() * 100000);
const timestamp = $now.toISO();

const analytics = input.analytics;

// Suppression is what makes the released output disclosable. If any cell was
// released while the safeguard could not be resolved, that is a governance
// failure, not merely a data-quality flag.
const safeguardResolved = analytics
  && analytics.safeguard
  && typeof analytics.safeguard.minimum_cell_size === "number";

const outcome = (safeguardResolved && (!analytics.flags || analytics.flags.length === 0))
  ? "released"
  : "released_with_flags";

const nistMapping = ["GOVERN-1.1", "MAP-3.4", "MEASURE-2.7", "MANAGE-4.1"];

const receipt = {
  receipt_id: receiptId,
  timestamp: timestamp,
  chained_from: {
    access_receipt_id: input.access_receipt_id || null,
    access_receipt_hash: input.access_receipt_hash || null
  },
  request: {
    measure: analytics.query.measure,
    condition_code: analytics.query.condition_code,
    group_by: analytics.query.group_by,
    bundle_path: analytics.query.bundle_path
  },
  decisions: [analytics],
  framework_mapping: {
    nist_ai_rmf: nistMapping,
    phipa_principles: ["limiting_use", "accountability"],
    mapping_note: "Disclosure safeguard (small-cell suppression) enforced at the analytics layer using the threshold declared by the governing policy."
  },
  outcome: outcome
};

// Hash for tamper-evidence, same discipline as the other audit nodes:
// stringify the receipt, hash, then attach the hash field last.
const hashable = JSON.stringify(receipt);
receipt.final_artifact_hash = crypto
  .createHash('sha256')
  .update(hashable)
  .digest('hex');

return [{ json: { receipt: receipt } }];
